import type { Metadata } from "next";
import { Geist, Geist_Mono } from "next/font/google";
import "./globals.css";

import { Providers } from "./providers";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

// Slice 075 — Logo integration. Favicon set, Open Graph card, and Twitter
// summary_large_image card declared via the Next.js Metadata API. Assets
// generated by `just regen-logo` from the canonical candidate-04 SVG.
//
// The favicon.ico uses the simplified favicon variant (slice 075 D4 —
// uniform 6px stroke collapses at 16px); apple-touch + PWA icons use
// the full mark (they render at sizes where the 16-line gradient reads
// cleanly).
//
// The OG + Twitter cards are server-side composited via Sharp (NOT
// image-model text rendering — slice 074 P0-A3 continues to apply).
// We ship them as light-theme cards: OG scrapers pick once at unfurl
// time and don't honor prefers-color-scheme.
export const metadata: Metadata = {
  title: "security-atlas",
  description:
    "Open-source, self-hostable GRC — one control graph, every framework.",
  icons: {
    icon: [
      { url: "/favicon.ico", sizes: "any" },
      { url: "/icon-192.png", type: "image/png", sizes: "192x192" },
      { url: "/icon-512.png", type: "image/png", sizes: "512x512" },
    ],
    apple: [{ url: "/apple-touch-icon.png", sizes: "180x180" }],
  },
  openGraph: {
    title: "security-atlas",
    description:
      "Open-source, self-hostable GRC — one control graph, every framework.",
    type: "website",
    siteName: "security-atlas",
    images: [
      {
        url: "/og-image.png",
        width: 1200,
        height: 630,
        alt: "security-atlas — open-source GRC platform",
      },
    ],
  },
  twitter: {
    card: "summary_large_image",
    title: "security-atlas",
    description:
      "Open-source, self-hostable GRC — one control graph, every framework.",
    images: [
      {
        url: "/twitter-card.png",
        width: 1200,
        height: 675,
        alt: "security-atlas — open-source GRC platform",
      },
    ],
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html
      lang="en"
      className={`${geistSans.variable} ${geistMono.variable} h-full antialiased`}
    >
      <body className="min-h-full flex flex-col">
        <Providers>{children}</Providers>
      </body>
    </html>
  );
}
